'use strict';

var _index = require('./index');

describe('packets', function () {
  describe('pingres', function () {
    describe('encode', function () {
      test('normal', function () {
        expect((0, _index.encode)({
          type: 'pingres'
        })).toEqual([
        // fixedHeader
        0xd0, // packetType + flags
        0] // remainingLength
        );
      });
    });

    describe('decode', function () {
      test('too short', function () {
        expect((0, _index.decode)(Uint8Array.from([0xd0]))).toBe(null);
      });

      test('normal', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        0xd0, // packetType + flags
        0] // remainingLength
        ))).toEqual({
          type: 'pingres'
        });
      });
    });
  });
});

/* eslint-env jest */